1. using Microsoft.ML;
2. using Microsoft.Extensions.ML;
3. using ChurnPredictor.Models;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // Train model and save to disk
8. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
9. TrainModel(
10.     Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"),
11.     modelPath);
12. 
13. // Register pooled prediction engine (thread-safe for web apps)
14. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
15.     .FromFile(modelPath);
16. 
17. var app = builder.Build();
18. 
19. app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");
20. 
21. app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
22. {
23.     var input = new CustomerData
24.     {
25.         Age = req.Age,
26.         Income = req.Income,
27.         Region = req.Region,
28.         PurchaseHistory = req.PurchaseHistory,
29.     };
30. 
31.     var prediction = pool.Predict(input);
32. 
33.     return Results.Ok(new
34.     {
35.         willChurn = prediction.Churned,
36.         probability = Math.Round(prediction.Probability, 4),
37.     });
38. });
39. 
40. app.Run();
