42. static void TrainModel(string dataPath, string modelPath)
43. {
44.     var mlContext = new MLContext(seed: 42);
45. 
46.     var data = mlContext.Data.LoadFromTextFile<CustomerData>(
47.         dataPath, hasHeader: true, separatorChar: ',');
48. 
49.     // Map "Yes"/"No" string to boolean label
50.     var labelMapping = new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false };
51.     var pipeline = mlContext.Transforms.Conversion.MapValue(
52.             "Label", labelMapping, inputColumnName: nameof(CustomerData.Churned))
53.         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
54.         .Append(mlContext.Transforms.Concatenate("Features",
55.             nameof(CustomerData.Age),
56.             nameof(CustomerData.Income),
57.             "RegionEncoded",
58.             nameof(CustomerData.PurchaseHistory)))
59.         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
60.         .Append(mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression());
61. 
62.     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
63. 
64.     var model = pipeline.Fit(split.TrainSet);
65. 
66.     var predictions = model.Transform(split.TestSet);
67.     var metrics = mlContext.BinaryClassification.Evaluate(predictions);
68. 
69.     Console.WriteLine("===== Churn Model Evaluation =====");
70.     Console.WriteLine($"  AUC:      {metrics.AreaUnderRocCurve:F4}");
71.     Console.WriteLine($"  Accuracy: {metrics.Accuracy:F4}");
72.     Console.WriteLine($"  F1 Score: {metrics.F1Score:F4}");
73. 
74.     mlContext.Model.Save(model, data.Schema, modelPath);
75.     Console.WriteLine($"Model saved to {modelPath}");
76. }
77. 
78. record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);
