 using Microsoft.ML;
 using Microsoft.Extensions.ML;
 using ChurnPredictor.Models;

 var builder = WebApplication.CreateBuilder(args);

 // Train model and save to disk
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
 TrainModel(
     Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"),
     modelPath);

 // Register pooled prediction engine (thread-safe for web apps)
 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
 {
     var input = new CustomerData
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory,
     };

     var prediction = pool.Predict(input);

     return Results.Ok(new
     {
         willChurn = prediction.Churned,
         probability = Math.Round(prediction.Probability, 4),
     });
 });

 app.Run();

 static void TrainModel(string dataPath, string modelPath)
 {
     var mlContext = new MLContext(seed: 42);

     var data = mlContext.Data.LoadFromTextFile<CustomerData>(
         dataPath, hasHeader: true, separatorChar: ',');

     // Map "Yes"/"No" string to boolean label
     var labelMapping = new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false };
     var pipeline = mlContext.Transforms.Conversion.MapValue(
             "Label", labelMapping, inputColumnName: nameof(CustomerData.Churned))
         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(CustomerData.Age),
             nameof(CustomerData.Income),
             "RegionEncoded",
             nameof(CustomerData.PurchaseHistory)))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression());

     var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

     var model = pipeline.Fit(split.TrainSet);

     var predictions = model.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions);

     Console.WriteLine("===== Churn Model Evaluation =====");
     Console.WriteLine($"  AUC:      {metrics.AreaUnderRocCurve:F4}");
     Console.WriteLine($"  Accuracy: {metrics.Accuracy:F4}");
     Console.WriteLine($"  F1 Score: {metrics.F1Score:F4}");

     mlContext.Model.Save(model, data.Schema, modelPath);
     Console.WriteLine($"Model saved to {modelPath}");
 }

 record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

